struct anchor_interval_t {
  std::int64_t begin{0};
  std::int64_t end{0};

  [[nodiscard]] bool empty() const { return end <= begin; }

  [[nodiscard]] std::int64_t length() const {
    return empty() ? 0 : end - begin;
  }
};

